<template>
	<view class="goods-info">
		<u-cell-group :border="false">
			<u-cell-item :arrow="false">
				<template #title>
					<view class="info">
						<u-image :src="goodsData.goods_img" :width="76" :height="76" border-radius="50%" />
						<text class="name">{{goodsData.goods_category_name}}</text>
					</view>
				</template>
				<template slot="right-icon">
					<view class="countdown">
						<text>剩余支付时间</text>
						<u-count-down :timestamp="orderData.expire_time" bg-color="#9B9FA8" color="#fff"
							@end="handelEnd"></u-count-down>
					</view>
				</template>
			</u-cell-item>
			<u-cell-item title="商品名称" :arrow="false" :value="orderData.goods_name"></u-cell-item>
			<u-cell-item v-if="goodsData.suk" title="商品规格" :arrow="false" :value="goodsData.suk"></u-cell-item>
			<u-cell-item title="订单编号" :arrow="false" :value="orderData.order_sn"></u-cell-item>
			<u-cell-item title="购买数量" :arrow="false">
				<template slot="right-icon"><text style="color: #909399;">x{{orderData.quantity}}</text></template>
			</u-cell-item>
			<!-- 下单模板-start -->
			<template v-if="orderData.recharge_info && orderData.recharge_info.length">
				<template v-if="orderData.recharge_info.length == 1">
					<u-cell-item :title="item.n" :arrow="false" v-for="item,index in orderData.recharge_info[0]"
						:key="index">
						<template v-if="item.t == 'images'">
							<view class="img-box">
								<view class="img-item" v-for="src,idx in item.v" :key="idx" @click.stop>
									<u-image width="60" height="60" @click="seeImg(idx,item.v)" border-radius="10"
										:src="src"></u-image>
								</view>
							</view>
						</template>
						<template v-else-if="item.t == 'checkbox'">
							{{item.v.join(',')}}
						</template>
						<template v-else>
							{{item.v}}
						</template>
					</u-cell-item>
				</template>
				<template v-else>
					<u-cell-item :arrow="false">
						<template #title>
							<text>{{orderData.recharge_info[0][0].n}} 下单数量</text>
						</template>
						<template slot="right-icon"><text
								style="color: #909399;">{{orderData.recharge_info.length}}</text></template>
					</u-cell-item>
				</template>
			</template>

			<u-cell-item v-if="orderData.promotions_price&& orderData.promotions_price>0" title="满减优惠"
				:arrow="false"><template slot="right-icon">
					<text class="c-red f34 fw-bolder">-￥{{orderData.promotions_price}}</text>
				</template>
			</u-cell-item>
			<!-- 下单模板-end -->
			<u-cell-item title="订单金额" :arrow="false">
				<template slot="right-icon">
					<text class="c-red f34 fw-bolder">￥{{orderData.total_price}}</text>
				</template>
			</u-cell-item>
			<u-cell-item title="优惠券优惠" :arrow="false" :border-bottom="false" v-if="orderData.coupon_id">
				<template slot="right-icon">
					<text class="c-red f34 fw-bolder">￥{{orderData.coupon_price}}</text>
				</template>
			</u-cell-item>
		</u-cell-group>
	</view>
</template>

<script>
	export default {
		components: {

		},
		inject: ['getGoodsData', 'getOrderData'],
		data() {
			return {

			}
		},
		computed: {
			goodsData() {
				return this.getGoodsData()
			},
			orderData() {
				return this.getOrderData()
			},
		},
		mounted() {

		},
		methods: {
			seeImg(index, urls) {
				uni.previewImage({
					current: index, // 当前显示图片的索引值
					urls: urls, // 需要预览的图片列表，photoList要求必须是数组

				})
			},
			handelEnd() {
				this.$util.msg('订单支付逾期！')
			},
		},
	}
</script>

<style scoped lang="scss" scoped>
	.goods-info {
		::v-deep {
			.u-cell-item-box {
				border-radius: 30rpx;
			}
		}

		.info {
			display: flex;
			align-items: center;
			gap: 20rpx;

			.name {
				font-weight: bolder;
			}
		}

		.countdown {
			color: #9b9fa8;
			display: flex;
			align-items: baseline;
			gap: 10rpx;
		}

		.img-box {
			display: flex;
			align-items: center;
			gap: 10rpx;

			.img-item {}
		}
	}
</style>