<template>
	<view class="page">
		<status-bar />
		<scroll-view enable-back-to-top scroll-y scroll-with-animation class="scroll-y">
			<view class="box mt-20">
				<goods-info />
			</view>
			<view class="box pb-20" v-if="order.order_sn">
				<pay-way ref="pay-way" type="pay" @change="handelPayWayChange" :money="order.total_price"
					:orderSn="order.order_sn" />
			</view>
		</scroll-view>

		<view class="footer">
			<view class="btn bg-red pay-btn" :class="{'btn-disabled':!order.expire_time?true:false}" @click="doBuy">立即支付
			</view>
		</view>
		<password-input :popupShow.sync="showPassInput" @ok="handelPasswordInputOk" />
		<u-modal v-model="showExpire" :zoom="false" :show-title="false" :show-cancel-button="false"
			confirm-color="#FF504B" @confirm="handelOrderExpire">
			<template #default>
				<view class="order-expire-content">
					<u-image :width="150" height="150" :src="$util.img('/statics/uni/img/pay/timeout.png')"></u-image>
					<text>订单已失效</text>
				</view>
			</template>
		</u-modal>
		<scanpay-qrcode-popup :qrcodeshow.sync="qrcodeshow" :title="payWay.title" :qrcodeurl="qrcodeUrl"
			:copymark="copyMark" @close="handelScanpyQrcodeClose" />
		<alipayuser-popup :show.sync="alipayuserPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
		<payjun-popup :show.sync="payjunPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
		
	</view>
</template>

<script>
	import StatusBar from '@/components/my-page-header/status-bar'
	import GoodsInfo from './components/order/goods-info'
	import PayWay from './components/PayWay'
	import PasswordInput from '@/components/password-input/index'
	import ScanpayQrcodePopup from '@/components/scanpay-qrcode-popup'
	import AlipayUserPopup from '@/components/alipayuser-popup'
import PayjunPopup from '@/components/payjun-popup'
	import {
		mapGetters
	} from 'vuex'
	export default {
		components: {
			'status-bar': StatusBar,
			'goods-info': GoodsInfo,
			'pay-way': PayWay,
			'password-input': PasswordInput,
			'scanpay-qrcode-popup': ScanpayQrcodePopup,
			'alipayuser-popup': AlipayUserPopup,
				'payjun-popup': PayjunPopup,
		},
		provide() {
			return {
				getGoodsData: () => this.goods,
				getOrderData: () => this.order
			}
		},
		data() {
			return {
				ordersn: '',

				goods: {},
				order: {},
				needTradePassword: false,

				payForm: {
					pay_type: '', //alipay=支付宝,wechat=微信支付,qqpay=QQ支付,balance=余额,code=加款卡
					order_sn: '', //支付订单号		
					trade_password: '', //(balance)交易密码
					pay_id: '', //通道id
				},
				payWay: {},

				showPassInput: false,
				showExpire: false,
				qrcodeshow: false,
				qrcodeUrl: '',
				copyMark: '',

				alipayuserPopupShow: false, //显示转账加款弹框
				payjunPopupShow: false, //显示骏卡支付弹框
				alipayuserPopupData: {}, //弹框渲染的内容
			}
		},
		computed: {
			...mapGetters(['deviceInfo']),
		},
		beforeRouteLeave(to, from, next) {
			// 导航离开该组件的对应路由时调用
			// 可以访问组件实例 `this`
			this.stopPayStatus()
			next();
		},
		onLoad(e) {
			const {
				ordersn,
				pay_type
			} = e
			if (!ordersn) {
				uni.showToast({
					icon: 'none',
					title: '订单编号不存在'
				})
				return
			}
			this.ordersn = ordersn
			this.payForm.order_sn = ordersn
			if (ordersn && pay_type) {
				this.payForm.pay_type = pay_type
				this.paystatusTimer = setInterval(() => {
					this.paystatus()
				}, 1000)

			}
			this.loadData()
		},
		methods: {
			handelPayWayChange(e) {
				this.payWay = e
			},
			async loadData(ordersn) {
				const {
					goods,
					order,
					need_trade_password,
				} = await this.$u.api.affirm({
					ordersn: this.ordersn
				})
				this.goods = goods
				this.order = order
				this.needTradePassword = need_trade_password

				if (!order.expire_time) {
					this.showExpire = true
				}
			},
			doBuy() {
				if (!this.order.expire_time)
					return
				if (!this.payWay) {
					this.$util.msg('请选择支付方式')
					return
				} else {
					this.payForm.pay_type = this.payWay.name
					this.payForm.pay_id = this.payWay.name == 'balance' ? '' : this.payWay.id
				}

				if (this.payWay.name == 'balance') {
					if (this.needTradePassword && !this.payForm.trade_password) {
						this.showPassInput = true
						return
					} else {
						this.$u.throttle(() => this.buy(), 1000)
					}

				} else {
					this.$u.throttle(() => this.buy(), 1000)
				}
			},
			paysuccess(url) {
			
			// console.log(this.sysconfig.change_site_info);
				if (!this.sysconfig.change_site_info) {
					this.$util.on(url);
				} else {
					uni.setStorage({
						key: 'bangOrderInfo',
						data: JSON.stringify(this.order)
					});
					this.$util.on('/pages/order/bang?pid='+this.userinfo.id);
				}
			
			
			},
			async buy() {
				// console.log(1231);
				try {
					var {
						url_type,
						url,
						order_sn,
						orderid,
						pay_data,
					} = await this.$u.api.pay(this.payForm)
				} catch (e) {
					this.payForm.trade_password = ''
					if (e.data.msg == "用户余额不足") {
						setTimeout(() => {
							this.$util.on('/pages/ucenter_sub/recharge');
						}, 1000)
					}
					return
				}
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
				}
				if (this.payForm.pay_type == 'balance') {
					this.$util.msg('支付成功');
					setTimeout(() => {
						// this.$util.on('/pages/order/info?id=' + orderid);
						this.paysuccess('/pages/order/info?id=' + orderid)
					}, 1000)
					return
				} else {
					this.paystatusTimer = setInterval(() => {
						this.paystatus()
					}, 2000)
				}
				let that = this
				switch (url_type) {
					case 1:
						this.qrcodeUrl = url
						//收款人身份
						if (this.payWay.name == 'alipayuser' && pay_data && pay_data.true_name) {
							this.copyMark = pay_data.true_name;
						} else {
							this.copyMark = '';
						}

						if (this.payWay.name == 'alipay' || this.payWay.name == 'alipayuser') {
							this.$util.openAppUrl(this.qrcodeUrl)
						}
						this.qrcodeshow = true

						break;
					case 2:
						//#ifdef MP-WEIXIN
						if (this.payWay.name == 'alipay') {
							this.qrcodeUrl = url
							this.qrcodeshow = true
						}
						//#endif
						//#ifdef H5
						window.location.href = url
						//#endif
						// #ifdef APP-PLUS
						this.qrcodeUrl = url
						this.qrcodeshow = true
						//#endif
						break;
					case 3:
						//#ifdef H5
						window.location.href = res.url
						//#endif
						break;
					case 4:
						//#ifdef H5
						jWeixin.config({
							debug: false, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
							appId: pay_data.appId, // 必填，公众号的唯一标识
							timestamp: pay_data.timeStamp, // 必填，生成签名的时间戳
							nonceStr: pay_data.nonceStr, // 必填，生成签名的随机串
							signature: pay_data.paySign, // 必填，签名
							jsApiList: [ //这里是需要用到的接口名称  
								'checkJsApi', //判断当前客户端版本是否支持指定JS接口  
								'onMenuShareAppMessage', //分享接口  
								'getLocation', //获取位置  
								'openLocation', //打开位置  
								'scanQRCode', //扫一扫接口  
								'chooseWXPay', //微信支付  
								'chooseImage', //拍照或从手机相册中选图接口  
								'previewImage', //预览图片接口  
								'uploadImage' //上传图片  
							], // 必填，需要使用的JS接口列表
							openId: this.userinfo.wxgzh_openid
						})
						//付款
						jWeixin.chooseWXPay({
							appId: pay_data.appId,
							timestamp: pay_data
								.timeStamp, // 支付签名时间戳，注意微信jssdk中的所有使用timestamp字段均为小写。但最新版的支付后台生成签名使用的timeStamp字段名需大写其中的S字符
							nonceStr: pay_data.nonceStr, // 支付签名随机串，不长于 32
							package: pay_data
								.package, // 统一支付接口返回的prepay_id参数值，提交格式如：prepay_id=\*\*\*）
							signType: pay_data.signType, // 签名方式，默认为'SHA1'，使用新版支付需传入'MD5'
							paySign: pay_data.paySign, // 支付签名
							success: function(res) {
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								// if (that.paystatusTimer) {
								// 	clearInterval(that.paystatusTimer)
								// }
								// that.$util.msg('支付成功');
								// setTimeout(() => {
								// 	that.$util.on('/pages/order/info?id=' + that.order_id);
								// }, 1000)

							},
							cancel: function(res) {
								that.$util.msg('取消支付');
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
							},
							fail: function(res) {
								that.$util.msg('付款失败');
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}

							}
						});
						//#endif
						break;
					case 5:
						// #ifdef MP
						let mp_pay_name = ''
						if (uni.requestOrderPayment) {
							mp_pay_name = 'requestOrderPayment'
						} else {
							mp_pay_name = 'requestPayment'
						}
						uni.showLoading({
							title: `支付中`
						})
						uni[mp_pay_name]({
							timeStamp: pay_data.timeStamp,
							nonceStr: pay_data.nonceStr,
							package: pay_data.package,
							signType: pay_data.signType,
							paySign: pay_data.paySign,
							success: function(res) {
								uni.hideLoading()
								that.$util.msg(res.msg)
							},
							fail: function(e) {
								uni.hideLoading();
								that.$util.msg('取消支付')
							},
							complete: function(e) {
								uni.hideLoading();
								if (e.errMsg == 'requestPayment:cancel' || e.errMsg ==
									'requestOrderPayment:cancel') return
								that.$util.msg('取消支付');
							},
						});
						// #endif
						break;
					case 6:
						// #ifdef APP-PLUS
						// console.log(res)
						uni.showLoading({
							mask: true,
							title: '支付中...'
						});
						uni.requestPayment({
							provider: 'wxpay',
							orderInfo: pay_data,
							success: (e) => {
								that.$util.msg(`支付成功`)
							},
							fail: (e) => {
								that.$util.msg(`支付失败`)
							},
							complete: () => {
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
								uni.hideLoading()
							},
						});
						// #endif
						break;
					case 7:
						// #ifdef APP-PLUS
						uni.showLoading({
							mask: true,
							title: '支付中...'
						});
						uni.requestPayment({
							provider: 'alipay',
							orderInfo: pay_data,
							success: (e) => {
								that.$util.msg(`支付成功`)
							},
							fail: (e) => {
								console.log(e)
								that.$util.msg(`支付失败`)
							},
							complete: (e) => {
								console.log(e)
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
								uni.hideLoading()
							},
						});
						// #endif
						break;
					case 8:
						this.alipayuserPopupData = {
							trade_sn: '',
							order_sn,
							pay_id: this.payForm.pay_id,
							...pay_data
						}
						if (this.alipayuserPopupData.is_trade_sn) {
							if (that.paystatusTimer) {
								clearInterval(that.paystatusTimer)
							}
						}
						if (this.alipayuserPopupData.is_need_account) {
							this.$util.msg('请使用支付宝提现账号付款')
							setTimeout(() => {
								this.$util.on('/pages/ucenter_sub/draw')
							}, 2000)
						} else
							this.alipayuserPopupShow = true
						break;
						case 9: //骏卡支付
							this.alipayuserPopupData = {
								trade_sn: '',
								order_sn: order_sn,
								pay_id: this.payForm.pay_id,
								...pay_data
							}
							
							this.payjunPopupShow = true
							break;
						
					default:
						break;
				}
			},
			async paystatus() {
				try {
					const {
						status,
						url
					} = await this.$u.api.payStatus({
						order_sn: this.ordersn

					})
					if (status == 1) {
						this.$util.msg('支付成功')
						clearInterval(this.paystatusTimer)
						setTimeout(() => {
							// this.$util.on(url);
							this.paysuccess(url)
						}, 1000)
					}
				} catch (e) {
					clearInterval(this.paystatusTimer)
				}
			},
			handelOrderExpire() {
				this.showExpire = false
				this.$util.back()
			},
			handelPasswordInputOk(e) {
				this.showPassInput = false
				this.payForm.trade_password = e
				this.buy()
			},
			stopPayStatus() {
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
					this.paystatusTimer = null
				}
			},
			handelAlipayUserOk({
				url
			}) {
				this.stopPayStatus()
				this.payjunPopupShow = false
				this.ordersn = ''
				this.order_id = ''
				setTimeout(() => {
					
					// this.$util.on(url)
					this.paysuccess(url)
					
				}, 1000)
			},
			handelScanpyQrcodeClose() {
				this.stopPayStatus()
			},
		}
	}
</script>


<style lang="scss" scoped scoped>
	.page {
		.scroll-y {
			height: calc(var(--vh) * 100 - 128rpx - var(--status-bar-height));
		}

		.box {
			padding-left: 20rpx;
			padding-right: 20rpx;
		}

		.order-expire-content {
			display: flex;
			flex-direction: column;
			align-items: center;
			justify-content: center;
			gap: 20rpx;
			padding: 60rpx 0;
		}

		.footer {
			position: fixed;
			z-index: 2;
			display: flex;
			align-items: center;
			justify-content: center;
			bottom: 0;
			left: 0;
			right: 0;
			width: 100%;
			background-color: #fff;
			padding: 20rpx;

			.pay-btn {
				width: 100%;
				height: 88rpx;
				display: flex;
				align-items: center;
				justify-content: center;
			}
		}
	}
</style>