<template>
	<view class="money-box">
		<view class="money-list">
			<view v-for="(item, index) in list" :key="index" class="money-item" :class="{ on: index == activeIndex }"
				@click="activeIndex = index">
				{{ item.money }}
			</view>
		</view>
		<view class="qrcode">
			<u-image v-if="img" :src="img" width="200" height="200" @click="preview(img)" />
		</view>
	</view>
</template>

<script>
	export default {
		components: {},
		props: {
			list: {
				type: Array,
				default: () => []
			}
		},
		data() {
			return {
				activeIndex: -1
			}
		},
		computed: {
			img() {
				const curr = this.list[this.activeIndex]
				return curr ? this.$util.img(curr.img) : ''
			}
		},
		watch: {},
		mounted() {
			if (this.list.length > 0) this.activeIndex = 0
		},
		methods: {
			preview(url) {
				uni.previewImage({
					urls: [url],
					current: url,
				})
			},
		}
	}
</script>

<style scoped lang="scss" scoped>
	.money-box {
		width: 100%;

		.money-list {
			display: grid;
			grid-template-columns: repeat(3, auto);
			grid-auto-rows: 80rpx;
			column-gap: 20rpx;
			row-gap: 20rpx;

			.money-item {
				cursor: pointer;
				display: flex;
				align-items: center;
				justify-content: center;
				border: 2rpx solid #e5e5e5;
				user-select: none;
			}

			.on {
				background-color: #409eff;
				color: #fff;
			}
		}

		.qrcode {
			margin-top: 20rpx;
		}
	}
</style>